// nav-guard.js
// Purpose: if the main site's index.html nav is ever regenerated by another
// process and the EKG teaching link is dropped, this script re-inserts it
// on page load. This file lives in ekg/ and is not touched by the main
// site's health-content publishing process.
(function () {
  function ensureEkgNav() {
    if (document.getElementById('nav-ekg')) return; // already present
    var link = document.createElement('a');
    link.href = 'ekg/index.html';
    link.id = 'nav-ekg';
    link.textContent = String.fromCodePoint(0x1FAC0) + ' 心電圖教學';
    // Prefer anchoring right after the breath-sounds link (same "extra
    // teaching section" grouping in the nav); fall back to the
    // health-education link, which has stayed stable even when the nav
    // container's class name changed (.main-nav -> .nav-r); fall back to
    // the nav container itself as a last resort.
    var afterLink = document.getElementById('nav-breath') || document.getElementById('nav-health');
    if (afterLink && afterLink.parentNode) {
      afterLink.insertAdjacentElement('afterend', link);
      return;
    }
    var nav = document.querySelector('.main-nav') || document.querySelector('.nav-r') || document.querySelector('nav');
    if (nav) nav.appendChild(link);
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', ensureEkgNav);
  } else {
    ensureEkgNav();
  }
})();
